cmdb_types.description:
Cmdb Types are custom fields integrated with the Jira Assets API

		{
		  "items": [
		    {
		      "description": "Service Field",
		      "jira_field": "customfield_10110",
		      "jira_object_type": "Service",
		      "required": true,
		      "value": "mydb-prod"
		    }
		  ]
		}

